// src/handlers/profile.ts
import { Request, Response } from 'express';
import { UserService } from '../services/user.service';

export async function updateProfile(req: Request, res: Response) {
  try {
    const userId = req.user?.id;

    if (!userId) {
      return res.status(401).json({ error: 'Unauthorized' });
    }

    const user = await UserService.findById(userId);

    if (!user) {
      return res.status(404).json({ error: 'User not found' });
    }

    // BUG: user.profile may be null/undefined for users who haven't set up their profile
    // This causes a TypeError when accessing preferences on undefined
    const currentPreferences = user.profile.preferences || {};

    const updatedPreferences = {
      ...currentPreferences,
      ...req.body.preferences
    };

    const updated = await UserService.updateProfile(userId, {
      ...req.body,
      preferences: updatedPreferences
    });

    return res.json(updated);
  } catch (error) {
    console.error('Profile update error:', error);
    return res.status(500).json({ error: 'Internal server error' });
  }
}
